/**
 * AgenticRepairPanel
 *
 * Polling panel that surfaces pending Knowledge Graph repair proposals
 * generated by the Agentic Self-Healing workflow.  Shown only when ≥1
 * proposal is awaiting human approval.
 *
 * Features
 * --------
 * - Polls GET /api/v1/healing/proposals every 30 s (and on mount)
 * - Premium diff view: proposed nodes + edges rendered in styled expandable
 *   cards with syntax-highlighted JSON for properties
 * - Projected ΔSc displayed in green pill (shows impact at a glance)
 * - Knowledge-gap context list per proposal
 * - "Approve Patch" (green) and "Reject" (red) actions for each proposal
 * - Live status badge updates after action (Committing… / Rejected)
 */

import React, { useCallback, useEffect, useRef, useState } from 'react'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface ProposedNode {
  node_hash: string
  node_type: string
  properties: Record<string, unknown>
  source_uri: string
  rationale: string
}

interface ProposedEdge {
  src_hash: string
  tgt_hash: string
  rel_type: string
  properties: Record<string, unknown>
  rationale: string
}

interface KnowledgeGap {
  gap_type: string
  missing_entity: string
  severity_score: number
  description: string
  affected_query_ids: string[]
}

interface Proposal {
  proposal_id: string
  thread_id: string
  status: string
  created_at: string
  expires_at: string
  proposed_nodes_count: number
  proposed_edges_count: number
  estimated_sc_delta: number
  rationale: string
  proposed_nodes: ProposedNode[]
  proposed_edges: ProposedEdge[]
  knowledge_gaps: KnowledgeGap[]
  verification_report: string | null
  drift_status: string | null
}

type ActionStatus = 'idle' | 'approving' | 'rejecting' | 'committed' | 'rejected' | 'error'

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const POLL_INTERVAL_MS = 30_000
const WEBHOOK_BASE = (() => {
  const env = (import.meta as any).env?.VITE_WEBHOOK_BASE_URL
  return ((env as string | undefined) || 'http://localhost:8008').replace(/\/$/, '')
})()

// ---------------------------------------------------------------------------
// Gap severity colour
// ---------------------------------------------------------------------------

function severityColor(score: number): string {
  if (score >= 0.7) return 'var(--status-error, #dc2626)'
  if (score >= 0.4) return 'var(--status-warn, #ca8a04)'
  return 'var(--status-ok, #16a34a)'
}

// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

function ScDeltaBadge({ delta }: { delta: number }) {
  const color = delta >= 0.1 ? '#16a34a' : delta >= 0.05 ? '#ca8a04' : '#6b7280'
  const sign = delta >= 0 ? '+' : ''
  return (
    <span
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 4,
        padding: '3px 10px',
        borderRadius: 999,
        background: delta >= 0.1 ? 'rgba(22,163,74,0.12)' : 'rgba(107,114,128,0.10)',
        border: `1px solid ${color}40`,
        color,
        fontWeight: 700,
        fontSize: 13,
        fontVariantNumeric: 'tabular-nums',
        letterSpacing: '0.02em',
      }}
    >
      {/* graph icon */}
      <svg width="12" height="12" viewBox="0 0 12 12" fill="none" aria-hidden="true">
        <circle cx="6" cy="2" r="1.5" fill={color} />
        <circle cx="2" cy="10" r="1.5" fill={color} opacity="0.7" />
        <circle cx="10" cy="10" r="1.5" fill={color} opacity="0.7" />
        <line x1="6" y1="3.5" x2="2.8" y2="8.7" stroke={color} strokeWidth="1" />
        <line x1="6" y1="3.5" x2="9.2" y2="8.7" stroke={color} strokeWidth="1" />
        <line x1="3.5" y1="10" x2="8.5" y2="10" stroke={color} strokeWidth="1" />
      </svg>
      ΔSc {sign}{(delta * 100).toFixed(1)}%
    </span>
  )
}

function JsonPreview({ data }: { data: unknown }) {
  const [expanded, setExpanded] = useState(false)
  const preview = JSON.stringify(data)
  const truncated = preview.length > 80
  return (
    <span style={{ fontFamily: 'monospace', fontSize: 11, color: 'var(--text-muted, #9ca3af)' }}>
      {expanded || !truncated ? preview : `${preview.slice(0, 80)}…`}
      {truncated && (
        <button
          onClick={() => setExpanded((e) => !e)}
          style={{ marginLeft: 4, fontSize: 10, padding: '0 4px', opacity: 0.7 }}
        >
          {expanded ? 'less' : 'more'}
        </button>
      )}
    </span>
  )
}

function NodeDiffRow({ node, index }: { node: ProposedNode; index: number }) {
  const [open, setOpen] = useState(false)
  return (
    <div
      style={{
        borderLeft: '3px solid rgba(34,197,94,0.6)',
        padding: '6px 10px',
        marginBottom: 6,
        background: 'rgba(34,197,94,0.04)',
        borderRadius: '0 6px 6px 0',
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 8 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 12, fontWeight: 600, color: 'var(--status-ok, #16a34a)' }}>
          <span style={{ opacity: 0.6 }}>+</span>
          <span style={{ fontFamily: 'monospace', fontSize: 11 }}>{node.node_hash.slice(0, 12)}…</span>
          <span style={{ fontWeight: 400, color: 'var(--text-muted, #6b7280)' }}>({node.node_type})</span>
        </div>
        <button
          onClick={() => setOpen((o) => !o)}
          aria-label={`toggle-node-${index}`}
          style={{ fontSize: 11, padding: '1px 8px', borderRadius: 4 }}
        >
          {open ? '▲ hide' : '▼ details'}
        </button>
      </div>
      <div style={{ fontSize: 12, marginTop: 4, opacity: 0.8 }}>
        {node.rationale}
      </div>
      {open && (
        <div style={{ marginTop: 8 }}>
          <div style={{ fontSize: 11, marginBottom: 4, color: 'var(--text-muted, #6b7280)' }}>
            source: <code style={{ fontSize: 10 }}>{node.source_uri}</code>
          </div>
          <table style={{ width: '100%', fontSize: 11, borderCollapse: 'collapse' }}>
            <tbody>
              {Object.entries(node.properties).map(([k, v]) => (
                <tr key={k} style={{ borderBottom: '1px solid var(--border, #333)' }}>
                  <td style={{ padding: '3px 6px', fontWeight: 600, width: 120, color: 'var(--text-muted, #9ca3af)' }}>{k}</td>
                  <td style={{ padding: '3px 6px' }}><JsonPreview data={v} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  )
}

function EdgeDiffRow({ edge }: { edge: ProposedEdge }) {
  return (
    <div
      style={{
        borderLeft: '3px solid rgba(99,102,241,0.6)',
        padding: '5px 10px',
        marginBottom: 5,
        background: 'rgba(99,102,241,0.04)',
        borderRadius: '0 6px 6px 0',
        fontSize: 12,
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontFamily: 'monospace', color: 'rgba(99,102,241,0.9)' }}>
        <span style={{ opacity: 0.6 }}>+</span>
        <span>{edge.src_hash.slice(0, 10)}…</span>
        <span style={{ fontSize: 11, color: 'var(--text-muted, #6b7280)' }}>─[{edge.rel_type}]─▶</span>
        <span>{edge.tgt_hash.slice(0, 10)}…</span>
      </div>
      <div style={{ marginTop: 3, opacity: 0.7 }}>{edge.rationale}</div>
    </div>
  )
}

function GapRow({ gap }: { gap: KnowledgeGap }) {
  return (
    <div
      style={{
        fontSize: 12,
        padding: '5px 10px',
        marginBottom: 4,
        borderLeft: `3px solid ${severityColor(gap.severity_score)}`,
        background: 'rgba(0,0,0,0.03)',
        borderRadius: '0 4px 4px 0',
      }}
    >
      <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 2 }}>
        <span
          style={{
            fontSize: 10,
            padding: '1px 6px',
            borderRadius: 999,
            background: `${severityColor(gap.severity_score)}20`,
            color: severityColor(gap.severity_score),
            fontWeight: 600,
          }}
        >
          {gap.gap_type}
        </span>
        <span style={{ fontFamily: 'monospace', fontSize: 11 }}>{gap.missing_entity}</span>
        <span style={{ marginLeft: 'auto', color: severityColor(gap.severity_score), fontWeight: 700, fontSize: 11 }}>
          sev {(gap.severity_score * 100).toFixed(0)}%
        </span>
      </div>
      <div style={{ opacity: 0.75 }}>{gap.description}</div>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Per-proposal card
// ---------------------------------------------------------------------------

function ProposalCard({
  proposal,
  onApprove,
  onReject,
  actionStatus,
}: {
  proposal: Proposal
  onApprove: (id: string) => void
  onReject: (id: string) => void
  actionStatus: ActionStatus
}) {
  const [diffOpen, setDiffOpen] = useState(false)
  const [gapsOpen, setGapsOpen] = useState(false)

  const isActing = actionStatus === 'approving' || actionStatus === 'rejecting'
  const isTerminal = actionStatus === 'committed' || actionStatus === 'rejected'

  return (
    <div
      style={{
        border: '1px solid var(--border, #2d2d2d)',
        borderRadius: 12,
        overflow: 'hidden',
        marginBottom: 16,
        background: 'var(--bg-card, var(--bg-muted, #161616))',
        boxShadow: '0 2px 16px rgba(0,0,0,0.25)',
      }}
    >
      {/* ── Header ── */}
      <div
        style={{
          padding: '14px 18px',
          borderBottom: '1px solid var(--border, #2d2d2d)',
          display: 'flex',
          alignItems: 'center',
          gap: 10,
          flexWrap: 'wrap',
          background: 'rgba(99,102,241,0.05)',
        }}
      >
        <span style={{ fontSize: 18 }}>🔧</span>
        <div style={{ flex: 1, minWidth: 180 }}>
          <div style={{ fontWeight: 700, fontSize: 14, color: 'var(--text, #f3f4f6)' }}>
            KG Repair Proposal
          </div>
          <div style={{ fontSize: 11, color: 'var(--text-muted, #6b7280)', marginTop: 2 }}>
            ID: <code style={{ fontFamily: 'monospace' }}>{proposal.proposal_id.slice(0, 18)}…</code>
          </div>
        </div>
        <ScDeltaBadge delta={proposal.estimated_sc_delta} />
        {proposal.drift_status === 'DRIFTING' && (
          <span
            style={{
              fontSize: 11,
              padding: '2px 8px',
              borderRadius: 999,
              background: 'rgba(220,38,38,0.12)',
              border: '1px solid rgba(220,38,38,0.4)',
              color: 'var(--status-error, #dc2626)',
              fontWeight: 600,
            }}
          >
            🚨 Drift triggered
          </span>
        )}
      </div>

      {/* ── Rationale ── */}
      <div style={{ padding: '12px 18px', fontSize: 13, color: 'var(--text, #d1d5db)', borderBottom: '1px solid var(--border, #2d2d2d)' }}>
        {proposal.rationale}
      </div>

      {/* ── Stats row ── */}
      <div
        style={{
          padding: '10px 18px',
          display: 'flex',
          gap: 20,
          flexWrap: 'wrap',
          borderBottom: '1px solid var(--border, #2d2d2d)',
          fontSize: 13,
        }}
      >
        <span>
          <strong style={{ color: 'rgba(34,197,94,0.9)' }}>+{proposal.proposed_nodes_count}</strong>
          <span style={{ color: 'var(--text-muted, #6b7280)', marginLeft: 4 }}>nodes</span>
        </span>
        <span>
          <strong style={{ color: 'rgba(99,102,241,0.9)' }}>+{proposal.proposed_edges_count}</strong>
          <span style={{ color: 'var(--text-muted, #6b7280)', marginLeft: 4 }}>edges</span>
        </span>
        {proposal.knowledge_gaps.length > 0 && (
          <span>
            <strong style={{ color: 'rgba(234,179,8,0.9)' }}>{proposal.knowledge_gaps.length}</strong>
            <span style={{ color: 'var(--text-muted, #6b7280)', marginLeft: 4 }}>gaps targeted</span>
          </span>
        )}
        {proposal.verification_report && (
          <span style={{ fontSize: 11, color: proposal.verification_report.startsWith('PASSED') ? '#16a34a' : '#ca8a04', marginLeft: 'auto' }}>
            {proposal.verification_report.split(':')[0]}
          </span>
        )}
      </div>

      {/* ── Collapsible: Knowledge Gaps ── */}
      {proposal.knowledge_gaps.length > 0 && (
        <div>
          <button
            onClick={() => setGapsOpen((o) => !o)}
            style={{
              width: '100%',
              textAlign: 'left',
              padding: '8px 18px',
              fontSize: 12,
              fontWeight: 600,
              background: 'transparent',
              border: 'none',
              borderBottom: '1px solid var(--border, #2d2d2d)',
              cursor: 'pointer',
              color: 'var(--text-muted, #9ca3af)',
              display: 'flex',
              alignItems: 'center',
              gap: 6,
            }}
          >
            {gapsOpen ? '▼' : '▶'} Diagnosed Knowledge Gaps ({proposal.knowledge_gaps.length})
          </button>
          {gapsOpen && (
            <div style={{ padding: '10px 18px', borderBottom: '1px solid var(--border, #2d2d2d)' }}>
              {proposal.knowledge_gaps.map((g, i) => (
                <GapRow key={i} gap={g} />
              ))}
            </div>
          )}
        </div>
      )}

      {/* ── Collapsible: Graph Diff ── */}
      <div>
        <button
          onClick={() => setDiffOpen((o) => !o)}
          style={{
            width: '100%',
            textAlign: 'left',
            padding: '8px 18px',
            fontSize: 12,
            fontWeight: 600,
            background: 'transparent',
            border: 'none',
            borderBottom: '1px solid var(--border, #2d2d2d)',
            cursor: 'pointer',
            color: 'var(--text-muted, #9ca3af)',
            display: 'flex',
            alignItems: 'center',
            gap: 6,
          }}
        >
          {diffOpen ? '▼' : '▶'} Proposed Graph Diff (
          <span style={{ color: 'rgba(34,197,94,0.9)' }}>+{proposal.proposed_nodes_count} nodes</span>,
          <span style={{ color: 'rgba(99,102,241,0.9)', marginLeft: 4 }}>+{proposal.proposed_edges_count} edges</span>)
        </button>
        {diffOpen && (
          <div style={{ padding: '12px 18px', borderBottom: '1px solid var(--border, #2d2d2d)' }}>
            {proposal.proposed_nodes.length > 0 && (
              <div style={{ marginBottom: 12 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted, #6b7280)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
                  Nodes
                </div>
                {proposal.proposed_nodes.map((node, i) => (
                  <NodeDiffRow key={node.node_hash} node={node} index={i} />
                ))}
              </div>
            )}
            {proposal.proposed_edges.length > 0 && (
              <div>
                <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted, #6b7280)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
                  Edges
                </div>
                {proposal.proposed_edges.map((edge, i) => (
                  <EdgeDiffRow key={`${edge.src_hash}-${edge.tgt_hash}-${i}`} edge={edge} />
                ))}
              </div>
            )}
            {proposal.proposed_nodes.length === 0 && proposal.proposed_edges.length === 0 && (
              <div style={{ fontSize: 12, color: 'var(--text-muted, #6b7280)' }}>No proposed changes in this patch.</div>
            )}
          </div>
        )}
      </div>

      {/* ── Action footer ── */}
      <div
        style={{
          padding: '14px 18px',
          display: 'flex',
          gap: 10,
          alignItems: 'center',
          justifyContent: 'flex-end',
        }}
      >
        {actionStatus === 'committed' && (
          <span style={{ color: '#16a34a', fontWeight: 700, fontSize: 13 }}>✓ Committed to Knowledge Graph</span>
        )}
        {actionStatus === 'rejected' && (
          <span style={{ color: 'var(--text-muted, #6b7280)', fontSize: 13 }}>✗ Rejected</span>
        )}
        {actionStatus === 'error' && (
          <span style={{ color: 'var(--status-error, #dc2626)', fontSize: 13 }}>⚠ Action failed — check daemon logs</span>
        )}
        {!isTerminal && (
          <>
            <button
              disabled={isActing}
              onClick={() => onReject(proposal.proposal_id)}
              aria-label="reject-proposal"
              style={{
                padding: '7px 18px',
                borderRadius: 8,
                border: '1px solid rgba(220,38,38,0.45)',
                background: 'rgba(220,38,38,0.07)',
                color: isActing ? 'var(--text-muted, #6b7280)' : 'var(--status-error, #dc2626)',
                cursor: isActing ? 'not-allowed' : 'pointer',
                fontWeight: 600,
                fontSize: 13,
                transition: 'all 0.15s',
              }}
            >
              {actionStatus === 'rejecting' ? 'Rejecting…' : 'Reject'}
            </button>

            <button
              disabled={isActing}
              onClick={() => onApprove(proposal.proposal_id)}
              aria-label="approve-proposal"
              style={{
                padding: '8px 22px',
                borderRadius: 8,
                border: 'none',
                background: isActing
                  ? 'rgba(22,163,74,0.35)'
                  : 'linear-gradient(135deg, #16a34a 0%, #15803d 100%)',
                color: '#fff',
                cursor: isActing ? 'not-allowed' : 'pointer',
                fontWeight: 700,
                fontSize: 14,
                boxShadow: isActing ? 'none' : '0 2px 8px rgba(22,163,74,0.35)',
                transition: 'all 0.2s',
                letterSpacing: '0.02em',
              }}
            >
              {actionStatus === 'approving' ? '⏳ Committing…' : '✓ Approve Patch'}
            </button>
          </>
        )}
      </div>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Main exported component
// ---------------------------------------------------------------------------

export function AgenticRepairPanel() {
  const [proposals, setProposals] = useState<Proposal[]>([])
  const [loading, setLoading] = useState(false)
  const [fetchError, setFetchError] = useState<string | null>(null)
  const [actionStatus, setActionStatus] = useState<Record<string, ActionStatus>>({})
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null)

  const fetchProposals = useCallback(async () => {
    try {
      const res = await fetch(`${WEBHOOK_BASE}/api/v1/healing/proposals`, {
        signal: AbortSignal.timeout(10_000),
      })
      if (!res.ok) throw new Error(`HTTP ${res.status}`)
      const data = await res.json()
      setProposals(data.proposals ?? [])
      setFetchError(null)
    } catch (err: unknown) {
      // Only surface an error if we've previously been loading — avoids noisy
      // startup errors when the daemon isn't reachable yet.
      if (loading) setFetchError((err as Error).message)
    } finally {
      setLoading(false)
    }
  }, [loading])

  useEffect(() => {
    setLoading(true)
    fetchProposals()
    timerRef.current = setInterval(fetchProposals, POLL_INTERVAL_MS)
    return () => {
      if (timerRef.current) clearInterval(timerRef.current)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const handleApprove = useCallback(
    async (proposalId: string) => {
      setActionStatus((s) => ({ ...s, [proposalId]: 'approving' }))
      try {
        const res = await fetch(
          `${WEBHOOK_BASE}/api/v1/healing/proposals/${encodeURIComponent(proposalId)}/approve`,
          {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ approved: true }),
          },
        )
        if (!res.ok) throw new Error(`HTTP ${res.status}`)
        setActionStatus((s) => ({ ...s, [proposalId]: 'committed' }))
      } catch {
        setActionStatus((s) => ({ ...s, [proposalId]: 'error' }))
      }
    },
    [],
  )

  const handleReject = useCallback(
    async (proposalId: string) => {
      setActionStatus((s) => ({ ...s, [proposalId]: 'rejecting' }))
      try {
        const res = await fetch(
          `${WEBHOOK_BASE}/api/v1/healing/proposals/${encodeURIComponent(proposalId)}/approve`,
          {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ approved: false, rejection_feedback: 'Rejected by admin.' }),
          },
        )
        if (!res.ok) throw new Error(`HTTP ${res.status}`)
        setActionStatus((s) => ({ ...s, [proposalId]: 'rejected' }))
      } catch {
        setActionStatus((s) => ({ ...s, [proposalId]: 'error' }))
      }
    },
    [],
  )

  // Render nothing when there are no proposals (no visual noise when healthy)
  if (!loading && !fetchError && proposals.length === 0) return null

  return (
    <section
      aria-label="agentic-repair-panel"
      style={{
        marginTop: 16,
        marginBottom: 8,
        border: '1px solid rgba(99,102,241,0.35)',
        borderRadius: 14,
        overflow: 'hidden',
        background: 'rgba(99,102,241,0.03)',
      }}
    >
      {/* Panel header */}
      <div
        style={{
          padding: '12px 20px',
          borderBottom: '1px solid rgba(99,102,241,0.2)',
          display: 'flex',
          alignItems: 'center',
          gap: 10,
          background: 'rgba(99,102,241,0.07)',
        }}
      >
        <svg width="18" height="18" viewBox="0 0 18 18" fill="none" aria-hidden="true">
          <circle cx="9" cy="3.5" r="2.5" fill="rgba(99,102,241,0.9)" />
          <circle cx="3" cy="14.5" r="2.5" fill="rgba(99,102,241,0.7)" />
          <circle cx="15" cy="14.5" r="2.5" fill="rgba(99,102,241,0.7)" />
          <line x1="9" y1="6" x2="3.8" y2="12.3" stroke="rgba(99,102,241,0.8)" strokeWidth="1.5" />
          <line x1="9" y1="6" x2="14.2" y2="12.3" stroke="rgba(99,102,241,0.8)" strokeWidth="1.5" />
          <line x1="5.5" y1="14.5" x2="12.5" y2="14.5" stroke="rgba(99,102,241,0.8)" strokeWidth="1.5" />
        </svg>
        <div>
          <div style={{ fontWeight: 700, fontSize: 15, color: 'var(--text, #f3f4f6)' }}>
            Agentic KG Repair Proposals
          </div>
          <div style={{ fontSize: 11, color: 'var(--text-muted, #6b7280)', marginTop: 1 }}>
            Autonomous self-healing proposals awaiting admin review
          </div>
        </div>
        <span
          style={{
            marginLeft: 'auto',
            padding: '3px 10px',
            borderRadius: 999,
            background: proposals.length > 0 ? 'rgba(99,102,241,0.15)' : 'rgba(107,114,128,0.1)',
            border: `1px solid ${proposals.length > 0 ? 'rgba(99,102,241,0.4)' : 'rgba(107,114,128,0.25)'}`,
            color: proposals.length > 0 ? 'rgba(99,102,241,0.9)' : 'var(--text-muted, #6b7280)',
            fontSize: 12,
            fontWeight: 700,
          }}
        >
          {loading ? '…' : `${proposals.length} pending`}
        </span>
      </div>

      {/* Panel body */}
      <div style={{ padding: '16px 20px' }}>
        {fetchError && (
          <div
            role="alert"
            style={{
              padding: '8px 12px',
              borderRadius: 8,
              border: '1px solid rgba(220,38,38,0.35)',
              background: 'rgba(220,38,38,0.06)',
              color: 'var(--status-error, #dc2626)',
              fontSize: 13,
              marginBottom: 12,
            }}
          >
            ⚠️ Could not reach healing daemon: {fetchError}
          </div>
        )}

        {loading && proposals.length === 0 && (
          <div style={{ fontSize: 13, color: 'var(--text-muted, #6b7280)', padding: '8px 0' }}>
            Loading proposals…
          </div>
        )}

        {proposals.map((proposal) => (
          <ProposalCard
            key={proposal.proposal_id}
            proposal={proposal}
            onApprove={handleApprove}
            onReject={handleReject}
            actionStatus={actionStatus[proposal.proposal_id] ?? 'idle'}
          />
        ))}
      </div>
    </section>
  )
}
